import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useParams } from 'react-router-dom';
import './App.css';

// --- КОМПОНЕНТ: МЕНЮ ---
const Menu = ({ onOrder }) => {
  const items = [
    { id: 1, name: 'Эспрессо', price: 150, img: '☕', desc: 'Крепкий и бодрящий' },
    { id: 2, name: 'Капучино', price: 250, img: '🥛', desc: 'С нежной молочной пенкой' },
    { id: 3, name: 'Круассан', price: 210, img: '🥐', desc: 'Свежеиспеченный, сливочный' }
  ];

  return (
    <div className="page fade-in">
      <h2>Наше Меню</h2>
      <div className="product-grid">
        {items.map(item => (
          <div key={item.id} className="product-card" onClick={() => onOrder(item)}>
            <div className="product-icon">{item.img}</div>
            <div className="product-info">
              <h3>{item.name}</h3>
              <p>{item.desc}</p>
              <span className="price">{item.price} ₽</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

// --- КОМПОНЕНТ: ДЕТАЛИ ЗАКАЗА ---
const OrderDetail = ({ orders }) => {
  const { id } = useParams();
  const order = orders.find(o => o.id === parseInt(id));

  if (!order) return <div className="page">Заказ не найден</div>;

  return (
    <div className="page fade-in">
      <Link to="/profile" className="back-link">← Назад к профилю</Link>
      <div className="detail-card">
        <div className={`status-banner ${order.status === 'Готов' ? 'ready' : 'processing'}`}>
          {order.status === 'Готов' ? '🎉 Готов к выдаче!' : '⏳ Готовим ваш кофе...'}
        </div>
        <h2>Заказ #{order.id}</h2>
        <div className="detail-row"><span>Позиция:</span> <strong>{order.description}</strong></div>
        <div className="detail-row"><span>Сумма:</span> <strong>{order.total_amount} ₽</strong></div>
        <div className="detail-row"><span>Время:</span> <strong>{new Date(order.created_at).toLocaleString()}</strong></div>
      </div>
    </div>
  );
};

// --- ОСНОВНОЕ ПРИЛОЖЕНИЕ ---
export default function App() {
  const [orders, setOrders] = useState([]);

  const fetchOrders = () => {
    fetch('http://localhost:8000/index.php')
      .then(res => res.json())
      .then(data => setOrders(Array.isArray(data) ? data : []));
  };

  useEffect(() => {
    fetchOrders();
    const interval = setInterval(fetchOrders, 3000);
    return () => clearInterval(interval);
  }, []);

  const handleOrder = async (item) => {
    await fetch('http://localhost:8000/index.php', {
      method: 'POST',
      body: JSON.stringify({ description: item.name, total_amount: item.price })
    });
    fetchOrders();
    alert('Заказ принят! Проверьте статус в профиле.');
  };

  return (
    <Router>
      <div className="paradise-app">
        <Routes>
          <Route path="/" element={<Menu onOrder={handleOrder} />} />
          <Route path="/profile" element={
            <div className="page fade-in">
              <h2>Мой Профиль</h2>
              <div className="user-info">
                <div className="avatar">☕</div>
                <div><h3>Любимый гость</h3><p>Бонусов: 450</p></div>
              </div>
              <h3>История заказов</h3>
              <div className="order-history">
                {orders.map(o => (
                  <Link key={o.id} to={`/order/${o.id}`} className="order-item-link">
                    <div className="order-item">
                      <span>#{o.id} - {o.description}</span>
                      <span className={`mini-status ${o.status === 'Готов' ? 'is-ready' : ''}`}>
                        {o.status}
                      </span>
                    </div>
                  </Link>
                ))}
              </div>
            </div>
          } />
          <Route path="/order/:id" element={<OrderDetail orders={orders} />} />
        </Routes>

        <nav className="bottom-nav">
          <Link to="/" className="nav-item">🍴 Меню</Link>
          <Link to="/profile" className="nav-item">👤 Профиль</Link>
        </nav>
      </div>
    </Router>
  );
}
